        line = Curl_get_line(buf, len, fp);
        fail_unless(line && !strcmp("LINE2 NEWLINE\n", line),
          "Second line failed (1)");
        line = Curl_get_line(buf, len, fp);
        abort_unless(line == NULL, "Missed EOF (1)");
        break;
