        line = Curl_get_line(buf, len, fp);
        fail_unless(line && !strcmp("LINE1\n", line),
          "First line failed (2)");
        line = Curl_get_line(buf, len, fp);
        fail_unless(line && !strcmp("LINE2 NONEWLINE\n", line),
          "Second line failed (2)");
        line = Curl_get_line(buf, len, fp);
        abort_unless(line == NULL, "Missed EOF (2)");
        break;
      case 2:
        line = Curl_get_line(buf, len, fp);
        fail_unless(line && !strcmp("LINE1\n", line),
