case CURLOPT_QUICK_EXIT:
  data->set.quick_exit = (0 != va_arg(param, long)) ? 1L:0L;
  break;
default:
  /* unknown tag and its companion, just ignore: */
  result = CURLE_UNKNOWN_OPTION;
  break;

raw_arguments.new_string:
  case CURLOPT_QUICK_EXIT:
    data->set.quick_exit = (0 != va_arg(param, long)) ? 1L:0L;
    break;
#ifdef USE_HTTP3
  case CURLOPT_H3_STREAM_PRIORITY:
    /*
     * Set HTTP/3 stream priority (RFC 9218) with urgency and incremental flags
     * Format: u=N[,i] where N is urgency level (0-7) and i is incremental flag
     */
    {
      const char *priority_str = va_arg(param, char *);
      if(priority_str) {
        char *endptr;
        long urgency = strtol(priority_str + 2, &endptr, 10);
        if(urgency >= 0 && urgency <= 7) {
          data->set.h3_stream_priority_urgency = (unsigned char)urgency;
          /* Check for incremental flag: ",i" after the urgency value */
          data->set.h3_stream_priority_incremental =
            (endptr[0] == ',' && endptr[1] == 'i') ? TRUE : FALSE;
        } else {
          result = CURLE_BAD_FUNCTION_ARGUMENT;
        }
      }
    }
    break;
#endif
  default:
    /* unknown tag and its companion, just ignore: */
    result = CURLE_UNKNOWN_OPTION;
    break;

